"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { LocalDB } from "@/lib/local-storage/db"
import { computeDailyReturns, computeAnnualizedReturn, computeSharpe, computeSortino, computeRollingReturns } from "@/lib/analysis/performance"
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts"

interface StrategyPerformanceProps {
  strategy: any
}

export function StrategyPerformance({ strategy }: StrategyPerformanceProps) {
  const [series, setSeries] = useState<any[]>([])
  const [metrics, setMetrics] = useState<{ annualReturn: number; sharpe: number; sortino: number }>({ annualReturn: 0, sharpe: 0, sortino: 0 })
  const [rolling, setRolling] = useState<{ date: string; rollingReturn: number }[]>([])

  useEffect(() => {
    let mounted = true

    const load = async () => {
      try {
        // fetch NAV histories for each fund in the strategy
        const allocations = strategy.fund_allocations || []
        const histories = await Promise.all(allocations.map((a: any) => LocalDB.getNAVHistory(a.fund_id)))

        // build date-indexed map of weighted NAV
        const dateMap: Record<string, number> = {}
        histories.forEach((hist: any[], idx) => {
          const alloc = (allocations[idx]?.allocation_percent || 0) / 100
          hist.forEach((h) => {
            if (!dateMap[h.date]) dateMap[h.date] = 0
            dateMap[h.date] += Number(h.nav) * alloc
          })
        })

        const dates = Object.keys(dateMap).sort()
        const points = dates.map((d) => ({ date: d, nav: Number(dateMap[d].toFixed(4)) }))

        if (!mounted) return
        setSeries(points)

        // compute performance metrics from strategy NAV series
        if (points.length >= 2) {
          const navHistory = points.map((p) => ({ id: p.date, fund_id: "", nav: p.nav, date: p.date }))
          const daily = computeDailyReturns(navHistory as any)
          const annualReturn = computeAnnualizedReturn(daily)
          const sharpe = computeSharpe(daily)
          const sortino = computeSortino(daily)
          setMetrics({ annualReturn, sharpe, sortino })
          // rolling returns (20-day by default)
          const rollingVals = computeRollingReturns(navHistory as any, 20)
          setRolling(rollingVals)
        }
      } catch (err) {
        console.error(err)
      }
    }

    load()
    return () => {
      mounted = false
    }
  }, [strategy])

  return (
    <Card>
      <CardHeader>
        <CardTitle>Strategy Performance</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="grid gap-4 md:grid-cols-3 mb-4">
          <div>
            <div className="text-sm text-gray-500">Annualized Return</div>
            <div className="text-lg font-semibold">{(metrics.annualReturn * 100).toFixed(2)}%</div>
          </div>
          <div>
            <div className="text-sm text-gray-500">Sharpe Ratio</div>
            <div className="text-lg font-semibold">{metrics.sharpe.toFixed(2)}</div>
          </div>
          <div>
            <div className="text-sm text-gray-500">Sortino Ratio</div>
            <div className="text-lg font-semibold">{metrics.sortino.toFixed(2)}</div>
          </div>
        </div>
        <div className="flex flex-col gap-4">
          <div style={{ width: "100%", height: 240 }}>
            <ResponsiveContainer>
              <LineChart data={series}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="date" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line type="monotone" dataKey="nav" stroke="#3b82f6" dot={false} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div style={{ width: "100%", height: 160 }}>
            <h4 className="text-sm font-medium mb-2">20-day Rolling Returns</h4>
            <ResponsiveContainer>
              <LineChart data={rolling}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="date" />
                <YAxis tickFormatter={(v) => `${(v * 100).toFixed(1)}%`} />
                <Tooltip formatter={(v: any) => `${(v * 100).toFixed(2)}%`} />
                <Line type="monotone" dataKey="rollingReturn" stroke="#10b981" dot={false} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div className="flex justify-end">
            <button
              className="px-3 py-1 bg-gray-100 rounded"
              onClick={() => {
                // build CSV: date, nav, rollingReturn
                const headers = ["date", "nav", "rollingReturn"]
                const rowsCsv = series.map((p) => {
                  const roll = rolling.find((r) => r.date === p.date)
                  return [p.date, p.nav, roll ? roll.rollingReturn : ""]
                })
                const csv = [headers.join(","), ...rowsCsv.map((r) => r.join(","))].join("\n")
                const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" })
                const url = URL.createObjectURL(blob)
                const a = document.createElement("a")
                a.href = url
                a.download = `${strategy.name || "strategy"}-performance.csv`
                a.click()
                URL.revokeObjectURL(url)
              }}
            >
              Export CSV
            </button>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}
