"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { LocalDB } from "@/lib/local-storage/db"
import {
  computeDailyReturns,
  computeAnnualizedReturn,
  computeSharpe,
  computeSortino,
} from "@/lib/analysis/performance"

export function ReportScheduler() {
  const [reports, setReports] = useState<any[]>([])
  const [name, setName] = useState("")
  const [type, setType] = useState("fund")
  const [targetId, setTargetId] = useState<string | undefined>(undefined)
  const [frequency, setFrequency] = useState("monthly")
  const [funds, setFunds] = useState<any[]>([])

  const load = async () => {
    const r = await LocalDB.getScheduledReports()
    setReports(r || [])
    const f = await LocalDB.getFunds()
    setFunds(f || [])
  }

  useEffect(() => {
    load()
  }, [])

  const create = async () => {
    if (!name) return alert('Provide a name')
    await LocalDB.createScheduledReport({ name, type, target_id: targetId, frequency })
    setName("")
    setType("fund")
    setTargetId(undefined)
    setFrequency("monthly")
    load()
  }

  const runAll = async () => {
    if (!confirm('Run all scheduled reports now?')) return
    for (const r of reports) {
      // run sequentially to avoid heavy parallel operations in demo
      // eslint-disable-next-line no-await-in-loop
      await runNow(r)
    }
    alert('All scheduled reports have been generated (downloaded).')
    load()
  }

  const remove = async (id: string) => {
    if (!confirm('Delete scheduled report?')) return
    await LocalDB.deleteScheduledReport(id)
    load()
  }

  const runNow = async (r: any) => {
    try {
      if (r.type === 'fund' && r.target_id) {
        const perf = await LocalDB.getFundPerformance(r.target_id)
        const rows = perf.map((p: any) => ({ fund_id: p.fund_id, period: p.period, returns: p.returns, sharpe: p.sharpe_ratio }))
        const csv = ['fund_id,period,returns,sharpe', ...rows.map((row: any) => `${row.fund_id},${row.period},${row.returns},${row.sharpe}`)].join('\n')
        const blob = new Blob([csv], { type: 'text/csv' })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = `${r.name || 'report'}.csv`
        a.click()
        URL.revokeObjectURL(url)
        // persist last run
        await LocalDB.setScheduledReportLastRun?.(r.id, new Date().toISOString())
        return
      }

      if (r.type === 'strategy' && r.target_id) {
        // richer strategy report: allocations + aggregated performance metrics
        const strategies = await LocalDB.getStrategies()
        const s = strategies.find((x: any) => x.id === r.target_id)
        const allocations = (s?.fund_allocations || []) as any[]

        // build date-indexed NAV map per fund (fill-forward when necessary)
        const navMaps: Record<string, Record<string, number>> = {}
        const allDates = new Set<string>()
        for (const a of allocations) {
          const hist = await LocalDB.getNAVHistory(a.fund_id)
          const map: Record<string, number> = {}
          let lastVal: number | null = null
          // ensure ascending order
          const sorted = hist.sort((x: any, y: any) => x.date.localeCompare(y.date))
          for (const h of sorted) {
            lastVal = h.nav
            map[h.date] = h.nav
            allDates.add(h.date)
          }
          navMaps[a.fund_id] = map
        }

        const dates = Array.from(allDates).sort()
        // build combined NAV time series
        const combined: { date: string; nav: number }[] = []
        // helper: for a fund get nav for date, fallback to nearest earlier date's nav
        function getNavForDate(fundId: string, date: string) {
          const map = navMaps[fundId] || {}
          if (map[date] !== undefined) return map[date]
          // find latest earlier date
          const sortedDates = Object.keys(map).sort()
          for (let i = sortedDates.length - 1; i >= 0; i--) {
            if (sortedDates[i] < date) return map[sortedDates[i]]
          }
          return undefined
        }

        for (const date of dates) {
          let total = 0
          let weightSum = 0
          for (const a of allocations) {
            const nav = getNavForDate(a.fund_id, date)
            if (nav === undefined) continue
            total += (a.allocation_percent / 100) * nav
            weightSum += a.allocation_percent / 100
          }
          if (weightSum === 0) continue
          // normalize by weight sum to avoid drift
          combined.push({ date, nav: total / weightSum })
        }

        // convert to NAVHistory-like for performance functions
        const combinedNavHistory = combined.map((c) => ({ id: `cmb-${c.date}`, fund_id: s.id, nav: c.nav, date: c.date }))
        const daily = computeDailyReturns(combinedNavHistory as any)
        const ann = computeAnnualizedReturn(daily)
        const sharpe = computeSharpe(daily)
        const sortino = computeSortino(daily)

        const headerLines = [
          `strategy_id,${s.id}`,
          `strategy_name,${s.name}`,
          `annualized_return,${ann}`,
          `sharpe,${sharpe}`,
          `sortino,${sortino}`,
          '',
        ]

        const allocRows = allocations.map((a: any) => `${a.fund_id},${a.allocation_percent}`)
        const csv = [...headerLines, 'fund_id,allocation', ...allocRows, '', 'date,combined_nav', ...combined.map((c) => `${c.date},${c.nav}`)].join('\n')
        const blob = new Blob([csv], { type: 'text/csv' })
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = `${r.name || 'strategy-report'}.csv`
        a.click()
        URL.revokeObjectURL(url)
        // persist last run
        await LocalDB.setScheduledReportLastRun?.(r.id, new Date().toISOString())
        return
      }

      // fallback: export transactions
      const transactions = await LocalDB.getAllTransactions()
      const csv = ['id,investor_id,fund_id,type,amount,units,nav,status,created_at', ...transactions.map((t: any) => `${t.id},${t.investor_id},${t.fund_id},${t.transaction_type},${t.amount},${t.units},${t.nav},${t.status},${t.created_at}`)].join('\n')
      const blob = new Blob([csv], { type: 'text/csv' })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${r.name || 'transactions'}.csv`
      a.click()
      URL.revokeObjectURL(url)
    } catch (err) {
      console.error(err)
      alert('Failed to generate report')
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Report Scheduler (Demo)</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-2">
          <div>
            <label className="block text-sm text-gray-700">Name</label>
            <Input value={name} onChange={(e: any) => setName(e.target.value)} />
          </div>

          <div className="mt-2">
            <label className="block text-sm text-gray-700">Type</label>
            <select className="border p-1 rounded w-full" value={type} onChange={(e) => setType(e.target.value)}>
              <option value="fund">Fund Performance</option>
              <option value="strategy">Strategy</option>
              <option value="transactions">Transactions</option>
            </select>
          </div>

          {type === 'fund' && (
            <div className="mt-2">
              <label className="block text-sm text-gray-700">Fund</label>
              <select className="border p-1 rounded w-full" value={targetId || ''} onChange={(e) => setTargetId(e.target.value || undefined)}>
                <option value="">-- select --</option>
                {funds.map((f) => (
                  <option key={f.id} value={f.id}>{f.fund_name}</option>
                ))}
              </select>
            </div>
          )}

          {type === 'strategy' && (
            <div className="mt-2 text-sm text-gray-500">Select strategy from the Strategies UI to create a scheduled strategy report (demo)</div>
          )}

          <div className="mt-3 flex gap-2">
            <Button onClick={create}>Create</Button>
            <Button variant="ghost" onClick={load}>Refresh</Button>
            <Button variant="outline" onClick={runAll}>Run All</Button>
          </div>
        </div>

        <div className="mt-4 space-y-2">
          {reports.map((r) => (
            <div key={r.id} className="flex items-center justify-between border rounded p-2">
              <div>
                <div className="font-semibold">{r.name}</div>
                <div className="text-xs text-gray-500">{r.type} {r.target_id ? `• ${r.target_id}` : ''} • {r.frequency || ''}</div>
              </div>
              <div className="flex gap-2">
                <Button size="sm" onClick={() => runNow(r)}>Run Now</Button>
                <Button size="sm" variant="ghost" onClick={() => remove(r.id)}>Delete</Button>
              </div>
            </div>
          ))}
          {reports.length === 0 && <div className="text-sm text-gray-500">No scheduled reports.</div>}
        </div>
      </CardContent>
    </Card>
  )
}
