"use client"

import { useEffect, useState } from "react"
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts"
import { LocalDB } from "@/lib/local-storage/db"

interface SeriesPoint {
  date: string
  [key: string]: any
}

interface ComparativeChartProps {
  fundIds?: string[]
}

export function ComparativeChart({ fundIds }: ComparativeChartProps) {
  const [data, setData] = useState<SeriesPoint[]>([])
  const [labels, setLabels] = useState<string[]>([])

  useEffect(() => {
    let mounted = true

    const load = async () => {
      try {
        const funds = await LocalDB.getFunds()
        const chosen = fundIds && fundIds.length > 0 ? fundIds : funds.slice(0, 2).map((f) => f.id)

        const histories = await Promise.all(chosen.map((id) => LocalDB.getNAVHistory(id)))

        // build date-indexed map
        const dateMap: Record<string, Record<string, number>> = {}
        histories.forEach((hist, idx) => {
          const key = `s${idx}`
          hist.forEach((h) => {
            if (!dateMap[h.date]) dateMap[h.date] = {}
            dateMap[h.date][key] = Number(h.nav)
          })
        })

        const sortedDates = Object.keys(dateMap).sort()
        const points: SeriesPoint[] = sortedDates.map((d) => ({ date: d, ...dateMap[d] }))

        if (!mounted) return
        setData(points)
        setLabels(chosen.map((id, i) => `Series ${i + 1}`))
      } catch (err) {
        console.error(err)
      }
    }

    load()
    return () => {
      mounted = false
    }
  }, [fundIds])

  if (!data || data.length === 0) {
    return <div className="rounded-lg border p-4 text-sm text-gray-500">No NAV history available for comparison.</div>
  }

  return (
    <div className="rounded-lg border p-4">
      <h3 className="text-lg font-semibold mb-2">Comparative NAV Chart</h3>
      <div style={{ width: "100%", height: 240 }}>
        <ResponsiveContainer>
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="date" />
            <YAxis />
            <Tooltip />
            <Legend />
            {labels.map((_, idx) => (
              <Line key={idx} type="monotone" dataKey={`s${idx}`} stroke={idx === 0 ? "#3b82f6" : "#f97316"} dot={false} />
            ))}
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  )
}
