"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
let LocalDBRef: any = null
import { StrategyBuilder } from "@/components/manager/strategy-builder"
import { StrategyPerformance } from "@/components/manager/strategy-performance"
import { planRebalance, executePlannedTrades } from "@/lib/analysis/rebalancer"

export function StrategyList() {
  const [strategies, setStrategies] = useState<any[]>([])
  const [editing, setEditing] = useState<any | null>(null)
  const [showBuilder, setShowBuilder] = useState(false)
  const [viewing, setViewing] = useState<string | null>(null)

  const load = async () => {
    if (!LocalDBRef) LocalDBRef = (await import("@/lib/local-storage/db")).LocalDB
    const s = await LocalDBRef.getStrategies()
    setStrategies(s || [])
  }

  useEffect(() => {
    load()
  }, [])

  const handleSaved = (s: any) => {
    setShowBuilder(false)
    setEditing(null)
    load()
  }

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this strategy?")) return
    if (!LocalDBRef) LocalDBRef = (await import("@/lib/local-storage/db")).LocalDB
    await LocalDBRef.deleteStrategy(id)
    load()
  }

  const runRebalance = async (s: any) => {
    try {
      const planned = await planRebalance(s, s.rebalancing?.threshold_percent || 2)
      if (!planned || planned.length === 0) return alert('No trades required (within threshold)')
      const preview = planned.map((p: any) => `${p.action.toUpperCase()} ${p.fund_id} ₹${p.amount}`).join('\n')
      if (!confirm(`Planned trades:\n\n${preview}\n\nExecute now as demo transactions?`)) return
      if (!LocalDBRef) LocalDBRef = (await import("@/lib/local-storage/db")).LocalDB
      await executePlannedTrades(s.manager_id || 'u-manager-1', planned)
      alert('Rebalance executed (demo).')
    } catch (err) {
      console.error(err)
      alert('Rebalance failed')
    }
  }

  return (
    <Card>
      <CardHeader className="flex items-center justify-between">
        <CardTitle>Strategies</CardTitle>
        <div>
          <Button onClick={() => { setEditing(null); setShowBuilder(true) }}>New</Button>
        </div>
      </CardHeader>
      <CardContent>
        {showBuilder && (
          <div className="mb-4">
            <StrategyBuilder initial={editing} onSaved={handleSaved} onCancel={() => { setShowBuilder(false); setEditing(null) }} />
          </div>
        )}

        <div className="space-y-3">
          {strategies.map((s) => (
            <div key={s.id} className="rounded-lg border p-3">
              <div className="flex items-center justify-between">
                <div>
                  <div className="font-semibold">{s.name}</div>
                  <div className="text-xs text-gray-500">Allocations: {s.fund_allocations.map((a: any) => `${a.allocation_percent}%`).join(", ")}</div>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" variant="outline" onClick={() => { setEditing(s); setShowBuilder(true) }}>Edit</Button>
                  <Button size="sm" variant="ghost" onClick={() => handleDelete(s.id)}>Delete</Button>
                  <Button size="sm" onClick={() => setViewing(viewing === s.id ? null : s.id)}>{viewing === s.id ? "Hide" : "View Performance"}</Button>
                  <Button size="sm" variant="secondary" onClick={() => runRebalance(s)}>Run Rebalance</Button>
                </div>
              </div>

              {viewing === s.id && (
                <div className="mt-3">
                  <StrategyPerformance strategy={s} />
                </div>
              )}
            </div>
          ))}
          {strategies.length === 0 && <div className="text-sm text-gray-500">No strategies yet.</div>}
        </div>
      </CardContent>
    </Card>
  )
}
